import React from 'react';
import logo from '../assets/logo.png';
import './Home.css';

export default function Home() {
  return (
    <div
      className="container"
      style={{
        backgroundImage: `url(${logo})`,
        backgroundRepeat: 'no-repeat',
        backgroundPosition: 'center top',
        backgroundSize: '150px 150px',
        paddingTop: '200px',
      }}
    >
      <header className="header">
        {/* <h1 className="logo">LogoRéservation</h1> */}
        <nav>
          <button className="btn">Connexion</button>
          <button className="btn">Inscription</button>
          <button className="btn primary">Nouvelle Réservation</button>
        </nav>
      </header>

      <main className="main">
        <h2>Bienvenue sur l'application de réservation</h2>
        <p>Réservez votre salle de réunion en toute simplicité.</p>
      </main>
    </div>
  );
}
